Function: ```go
package main

import (
	"context"
	"errors"
	"fmt"
	"math/rand"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"
)

type Signal int

const (
	Unspecified Signal = iota
	// Kill signals that a kill switch will accept
	Kill
	// Restart signals that a kill switch will accept
	Restart
)

func (s Signal) String() string {
	switch s {
	case Kill:
		return "kill"
	case Restart:
		return "restart"
	default:
		return "unspecified"
	}
}

type KillSwitch interface {
	// Signal the kill switch should perform an action
	Signal(Signal) error
	// Done is a channel that is closed when the kill switch has finished shutting down.
	Done() <-chan struct{}
}

type killSwitchImpl struct {
	action chan Signal
	done   chan struct{}
}

func (k *killSwitchImpl) Signal(s Signal) error {
	if s == Unspecified {
		return errors.New("invalid signal")
	}

	select {
	case k.action <- s:
		return nil
	default:
		return errors.New("signal already sent")
	}
}

func (k *killSwitchImpl) Done() <-chan struct{} {
	return k.done
}

func NewKillSwitch() KillSwitch {
	return &killSwitchImpl{
		action: make(chan Signal, 1),
		done:   make(chan struct{}),
	}
}

// haystack is a needle in a haystack
var haystack = "haystack"
var needle = "needle"

func main() {
	logger := func(format string, args ...any) {
		fmt.Printf("%s %s\n", time.Now().UTC().Format(time.RFC3339), fmt.Sprintf(format, args...))
	}

	result, err := run(logger)
	if err != nil {
		logger("run failed: %v", err)
		os.Exit(1)
	}
	logger("done with result: %s", result)
	os.Exit(0)
}

// run is the main run function.
func run(logger func(string, ...any)) (string, error) {
	killSwitch := NewKillSwitch()

	// start the server in the background
	server := &http.Server{Addr: ":8080", Handler: http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		logger("handling request")
		time.Sleep(time.Duration(rand.Intn(1000)) * time.Millisecond)
		w.Write([]byte(needle))
	})}
	go func() {
		if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			logger("server failed: %v", err)
			killSwitch.Signal(Kill)
		}
	}()
	logger("server started")

	// wait for a signal
	ctx, cancel := signal.NotifyContext(context.Background(), os.Interrupt, syscall.SIGTERM)
	defer cancel()

	var signal Signal

	select {
	case <-ctx.Done():
		signal = Kill
		logger("received kill signal")
	case <-time.After(1 * time.Second):
		signal = Restart
		logger("restarting")
	}

	// signal the kill switch
	if err := killSwitch.Signal(signal); err != nil {
		return "", fmt.Errorf("signal kill switch: %w", err)
	}

	// drain the server
	ctx, cancel = context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	logger("shutting down server")
	if err := server.Shutdown(ctx); err != nil {
		return "", fmt.Errorf("shutdown server: %w", err)
	}

	logger("waiting for done from kill switch")
	<-killSwitch.Done()

	return haystack, nil
}
